input.command:
node -e "
const k=(process.env.RENDER_API_KEY??'').trim();
console.log('RENDER_API_KEY len:'+k.length+' prefix:'+k.slice(0,4)+' mask:'+(k?k.slice(0,4)+'****'+k.slice(-4):'(empty)'));
if(!k){console.log('EMPTY');process.exit(0);}
const H={Authorization:'Bearer '+k,Accept:'application/json'};
(async()=>{
  const r1=await fetch('https://api.render.com/v1/services/srv-d7t9ivreo5us73ftose0',{headers:H});
  const b1=await r1.json().catch(()=>({}));
  console.log('RENDER_SERVICE_HTTP:'+r1.status+' name:'+(b1.name??b1.service?.name??null)+' suspended:'+(b1.suspended??b1.service?.suspended??null));
  const r2=await fetch('https://api.render.com/v1/services/srv-d7t9ivreo5us73ftose0/deploys?limit=1',{headers:H});
  const b2=await r2.json().catch(()=>[]);
  const d=Array.isArray(b2)?b2[0]?.deploy:null;
  console.log('LAST_DEPLOY_HTTP:'+r2.status+' id:'+(d?.id??null)+' status:'+(d?.status??null)+' commit:'+(d?.commit?.id??'').slice(0,8)+' finished:'+(d?.finishedAt??null));
})();
"

